@props(['optionsRoute'=>'passkey.login-options','submitRoute'=>'passkey.login','label'=>__('Sign in with a passkey'),'loadingLabel'=>__('Authenticating...'),'separator'=>__('Or continue with email')])
@assets @vite('resources/js/passkeys.js') @endassets
<div x-data="{supported:false,loading:false,error:null,init(){this.supported=Boolean(window.Passkeys?.isSupported());window.addEventListener('passkeys:ready',()=>this.supported=Boolean(window.Passkeys?.isSupported()),{once:true})},async verify(){this.loading=true;this.error=null;try{const r=await window.Passkeys.verify({routes:{options:'{{ route($optionsRoute) }}',submit:'{{ route($submitRoute) }}'}});Livewire.navigate(r.redirect||'/dashboard')}catch(e){if(e.constructor?.name!=='UserCancelledError')this.error=e.message}finally{this.loading=false}}}">
<template x-if="supported"><div class="grid gap-4"><x-ui.button variant="secondary" class="w-full" x-on:click="verify()" x-bind:disabled="loading"><span x-text="loading ? @js($loadingLabel) : @js($label)"></span></x-ui.button><p x-show="error" x-text="error" class="text-center text-sm text-red-600"></p><div class="flex items-center gap-3 text-xs uppercase text-slate-400"><span class="h-px flex-1 bg-slate-200"></span>{{ $separator }}<span class="h-px flex-1 bg-slate-200"></span></div></div></template>
</div>
